lesson.example:
ports = [22, 80, 443]
for p in ports:
    print(f"Port {p}")

services = ["ssh", "http", "telnet", "ftp"]
for svc in services:
    if "tel" in svc:
        print(f"{svc}  <-- insecure")
    else:
        print(svc)

record = {"domain": "corp.com", "ns": ["ns1.corp.com", "ns2.corp.com"]}
for server in record["ns"]:
    print(server)

ips = ["192.168.1.1", "10.0.0.1", "172.16.0.1"]
count = 0
for ip in ips:
    if ip.startswith("10.") or ip.startswith("172."):
        count += 1
print(f"Private (non-192) addresses: {count}")
